Drupal.behaviors.EurekaMap={attach(a){const t=once("EurekaMap",".js-map",a);t.length&&t.forEach(a=>{const t=a.dataset.mapLat,e=a.dataset.mapLon,o=a.dataset.mapZoom,p=a.dataset.mapPopup,n=L.icon({iconUrl:"/themes/custom/eureka/images/icons/map-pin.svg",iconSize:[21,30]}),r=L.map(a).setView([t,e],o);L.tileLayer("https://tile.openstreetmap.org/{z}/{x}/{y}.png",{maxZoom:25,attribution:'&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a>'}).addTo(r);const s=L.marker([t,e],{icon:n}).addTo(r);p&&s.bindPopup(p)})}};